use regex::Regex;

fn main() {
    let re = Regex::new(r"foo").unwrap();
    for line in std::fs::read_to_string("input.txt").unwrap().lines() {
        if re.is_match(line) {
            println!("Match: {}
", line);
        }
    }
}
